const response = $input.first().json;
let totalSteps = 0;

// Mengecek apakah Google Health mengembalikan data agregasi langkah
if (response.rollupDataPoints && response.rollupDataPoints.length > 0) {
  const stepsData = response.rollupDataPoints[0].steps;

  // Mengambil angka akumulasi (countSum)
  if (stepsData && stepsData.countSum) {
    totalSteps = stepsData.countSum;
  }
}

return [{
  json: {
    logged_date: $now.setZone('Asia/Jakarta').toISODate(),
    steps_count: totalSteps,
    wakatime_coding_hours: 0
  }
}];

// Mengambil data dari node sebelumnya
const healthData = $('Code in JavaScript').item.json; 
const calendarEvents = $input.all(); 

let sleepSessions = [];

// VARIABEL METRIK HARIAN
let codingHours = 0;
let projectFocusHours = 0;
let campusActivityHours = 0;
let workoutMinutes = 0;
let holidayHours = 0;
let freeTimeHours = 0;

// 1. HITUNG TOTAL KODING & AKTIVITAS BARU HARIAN
calendarEvents.forEach(item => {
    const ev = item.json;
    if (!ev.start || !ev.end || !ev.summary) return;
    const summary = ev.summary.toLowerCase();

    // Kalkulasi durasi acara
    const start = new Date(ev.start.dateTime || ev.start.date).getTime();
    const end = new Date(ev.end.dateTime || ev.end.date).getTime();
    const durationHours = (end - start) / (1000 * 60 * 60);
    const durationMinutes = (end - start) / (1000 * 60);

    // a. Waktu Koding Umum
    if (summary.includes('koding') || summary.includes('coding') || summary.includes('ngoding')) {
        codingHours += durationHours;
    }

    // b. Project Focus (Termasuk nama proyek spesifik Anda)
    if (summary.includes('project') || summary.includes('proyek') || summary.includes('ruang pengajar') || summary.includes('monoestarifish') || summary.includes('server') || summary.includes('smartcard')) {
        projectFocusHours += durationHours;
    }

    // c. Campus Activity (Termasuk kepanitiaan)
    if (summary.includes('kuliah') || summary.includes('kelas') || summary.includes('kampus') || summary.includes('kelompok') || summary.includes('rapat')) {
        campusActivityHours += durationHours;
    }

    // d. Workout / Olahraga
    if (summary.includes('olahraga') || summary.includes('workout') || summary.includes('lari') || summary.includes('gym')) {
        workoutMinutes += durationMinutes;
    }

    // e. Liburan
    if (summary.includes('liburan') || summary.includes('holiday') || summary.includes('piknik') || summary.includes('healing')) {
        holidayHours += durationHours;
    }

    // f. Free Time / Waktu Santai
    if (summary.includes('santai') || summary.includes('free time') || summary.includes('waktu luang') || summary.includes('me time')) {
        freeTimeHours += durationHours;
    }
});

// 2. BEDAH SESI TIDUR & EKSTRAKSI SLEEP AS ANDROID
calendarEvents.forEach(item => {
    const ev = item.json;
    if (!ev.start || !ev.end || !ev.summary) return;
    const summary = ev.summary.toLowerCase();

    // Disederhanakan agar kata 'istirahat' bisa Anda gunakan untuk free time jika mau
    if (summary.includes('tidur') || summary.includes('sleep')) { 
        const startStr = ev.start.dateTime || ev.start.date;
        const endStr = ev.end.dateTime || ev.end.date;
        const durationMinutes = Math.round((new Date(endStr).getTime() - new Date(startStr).getTime()) / (1000 * 60));

        const rawDesc = ev.description || "";
        const cleanDesc = rawDesc.replace(/<[^>]*>?/gm, ''); 

        let deepSleepMinutes = null;
        let sleepType = durationMinutes > 120 ? 'Tidur Utama' : 'Tidur Siang / Ekstra';

        const deepSleepMatch = cleanDesc.match(/Tidur nyenyak:\s*(\d+)%/i) || cleanDesc.match(/Deep sleep:\s*(\d+)%/i);

        if (deepSleepMatch) {
            const percentage = parseInt(deepSleepMatch[1]);
            deepSleepMinutes = Math.round((percentage / 100) * durationMinutes);
            sleepType = 'Tidur Utama'; 
        } else if (cleanDesc.includes('Sleep as Android')) {
            sleepType = 'Tidur Utama';
        }

        sleepSessions.push({
            session_start: startStr,
            session_end: endStr,
            sleep_duration_minutes: durationMinutes,
            sleep_type: sleepType,
            deep_sleep_minutes: deepSleepMinutes
        });
    }
});

// 3. RAKIT PAYLOAD UNTUK DATABASE
let results = [];
let aggregatesAssigned = false;

// Skenario A: Jika tidak ada data tidur sama sekali hari ini 
if (sleepSessions.length === 0) {
    results.push({
        json: {
            logged_date: healthData.logged_date,
            session_start: new Date(healthData.logged_date).toISOString(),
            steps_count: healthData.steps_count,
            wakatime_coding_hours: parseFloat(codingHours.toFixed(2)),
            project_focus_hours: parseFloat(projectFocusHours.toFixed(2)),
            campus_activity_hours: parseFloat(campusActivityHours.toFixed(2)),
            workout_minutes: Math.round(workoutMinutes),
            holiday_hours: parseFloat(holidayHours.toFixed(2)),
            free_time_hours: parseFloat(freeTimeHours.toFixed(2)),
            sleep_type: 'Tanpa Data Tidur'
        }
    });
} 
// Skenario B: Memasukkan sesi tidur (Utama dan Ekstra)
else {
    sleepSessions.forEach(session => {
        let payload = {
            logged_date: healthData.logged_date,
            session_start: session.session_start,
            session_end: session.session_end,
            sleep_duration_minutes: session.sleep_duration_minutes,
            sleep_type: session.sleep_type,
            deep_sleep_minutes: session.deep_sleep_minutes
        };

        // Tempelkan metrik harian HANYA ke satu baris (Tidur Utama) agar tidak duplikat di DB
        if (!aggregatesAssigned && session.sleep_type === 'Tidur Utama') {
            payload.steps_count = healthData.steps_count;
            payload.wakatime_coding_hours = parseFloat(codingHours.toFixed(2));
            payload.project_focus_hours = parseFloat(projectFocusHours.toFixed(2));
            payload.campus_activity_hours = parseFloat(campusActivityHours.toFixed(2));
            payload.workout_minutes = Math.round(workoutMinutes);
            payload.holiday_hours = parseFloat(holidayHours.toFixed(2));
            payload.free_time_hours = parseFloat(freeTimeHours.toFixed(2));
            aggregatesAssigned = true;
        }

        results.push({ json: payload });
    });

    // Jika kebetulan hari itu hanya ada Tidur Ekstra tanpa Utama
    if (!aggregatesAssigned && results.length > 0) {
        results[0].json.steps_count = healthData.steps_count;
        results[0].json.wakatime_coding_hours = parseFloat(codingHours.toFixed(2));
        results[0].json.project_focus_hours = parseFloat(projectFocusHours.toFixed(2));
        results[0].json.campus_activity_hours = parseFloat(campusActivityHours.toFixed(2));
        results[0].json.workout_minutes = Math.round(workoutMinutes);
        results[0].json.holiday_hours = parseFloat(holidayHours.toFixed(2));
        results[0].json.free_time_hours = parseFloat(freeTimeHours.toFixed(2));
    }
}

return results;
